validator = AssistantAgent(
    name="Validator",
    system_message="Validate API results and decide next step: approve/rollback/retry"
)

def conditional_branch(result):
    if result['status'] == 'success' and result['amount'] < 1000:
        return 'execute'
    elif result['status'] == 'error':
        return 'rollback'
    return 'human_review'

# Used by validator agent
manager.add_agent(validator)

import requests

def safe_api_call(params):
    idempotency_key = params['idempotency_key']
    response = requests.post(
        'https://api.example.com/workflows',
        json=params,
        headers={'Idempotency-Key': idempotency_key}
    )
    if response.status_code == 409:
        return {'status': 'idempotent', 'action': 'skip'}
    return response.json()

api_agent.register_for_llm(name="call_api")(safe_api_call)

