WORKFLOW_SPEC = {
    'steps': ['validate', 'api_call', 'human_review', 'execute'],
    'allowed_apis': ['payment', 'notification'],
    'max_amount': 5000
}

def verify_action_correctness(proposed_action):
    step = proposed_action['step']
    if step not in WORKFLOW_SPEC['steps']:
        return False

    api = proposed_action.get('api')
    if api and api not in WORKFLOW_SPEC['allowed_apis']:
        return False

    return vex.verify({
        'type': 'action_correctness',
        'spec': WORKFLOW_SPEC,
        'action': proposed_action
    })['valid']

validator.register_for_llm(name="verify_action")(verify_action_correctness)

def validate_permissions_and_rollback(context):
    action = context['action']
    user_permissions = context['user_permissions']

    # Permission check
    required_perm = f"{action['type']}:{action['resource']}"
    if required_perm not in user_permissions:
        return {'approved': False, 'reason': 'insufficient_permissions'}

    # Idempotency/rollback check
    if 'idempotency_key' not in action:
        action['idempotency_key'] = vex.generate_idempotency_key(action)

    verdict = vex.verify({
        'type': 'permission_validation',
        'action': action,
        'rollback_enabled': True
    })

    return verdict

supervisor.register_for_llm(name="permission_check")(validate_permissions_and_rollback)
